```typescript
abstract class CompteBancaire {
  constructor(public numero: string, protected solde: number) {}

  deposer(montant: number): void {
    this.solde += montant;
  }

  afficherSolde(): string {
    return `Compte ${this.numero} : ${this.solde} FCFA`;
  }

  abstract calculerInterets(): number;
}

class CompteEpargne extends CompteBancaire {
  constructor(numero: string, solde: number) {
    super(numero, solde);
  }

  calculerInterets(): number {
    return this.solde * 0.05; // 5% d'intérêts
  }
}

class CompteCourant extends CompteBancaire {
  constructor(numero: string, solde: number) {
    super(numero, solde);
  }

  calculerInterets(): number {
    return 0; // Pas d'intérêts
  }
}
```

```typescript
const epargne = new CompteEpargne("CEP001", 100000);
epargne.deposer(25000);
console.log(epargne.afficherSolde()); // Compte CEP001 : 125000 FCFA
console.log(epargne.calculerInterets()); // 6250 (125000 * 0.05)
```

```typescript
class Employe {
  constructor(protected salaireBase: number) {}

  calculerSalaire(): number {
    return this.salaireBase;
  }
}

class Manager extends Employe {
  constructor(salaireBase: number, private prime: number) {
    super(salaireBase);
  }

  calculerSalaire(): number {
    return super.calculerSalaire() + this.prime;
  }
}
```

```typescript
abstract class Evaluation {
  constructor(public matiere: string, public coefficient: number) {}

  abstract calculerNoteMax(): number;
  abstract getNoteFinale(): number;

  description(): string {
    return `Evaluation en ${this.matiere} (coeff ${this.coefficient})`;
  }
}

class Devoir extends Evaluation {
  constructor(matiere: string, coefficient: number, private noteObtenue: number) {
    super(matiere, coefficient);
  }

  calculerNoteMax(): number { return 20; }
  getNoteFinale(): number { return this.noteObtenue; }
}

class Examen extends Evaluation {
  constructor(matiere: string, coefficient: number, private noteObtenue: number) {
    super(matiere, coefficient);
  }

  calculerNoteMax(): number { return 40; }
  getNoteFinale(): number { return this.noteObtenue; }
}

class Projet extends Evaluation {
  constructor(matiere: string, coefficient: number, private noteObtenue: number, private penaliteRetard: number) {
    super(matiere, coefficient);
  }

  calculerNoteMax(): number { return 30; }
  getNoteFinale(): number { 
    const noteApresPenalite = this.noteObtenue - this.penaliteRetard;
    return noteApresPenalite < 0 ? 0 : noteApresPenalite;
  }
}
```

```typescript
class Vehicule {
  constructor(public marque: string, public vitesseMax: number) {}
  sePresenter(): string {
    return `Je suis un véhicule de marque ${this.marque}`;
  }
}

class Moto extends Vehicule {
  constructor(marque: string, vitesseMax: number, public aSidecar: boolean) {
    super(marque, vitesseMax);
  }

  override sePresenter(): string {
    return `Je suis une moto de marque ${this.marque}`;
  }
}
```
L’intérêt du mot-clé <code>override</code> est d’augmenter la maintenabilité et la sécurité : si la méthode parente est supprimée ou renommée, TypeScript générera une erreur, évitant ainsi des bugs silencieux.
